import { Suspense } from 'react';
import { 
  getGamificationStats, 
  calculateNextLevelProgress 
} from '@/src/lib/supabase/queries/gamificacao-real';
import { GamificationPanel } from '@/src/components/gamification/GamificationPanel';
import { Card, CardContent } from '@/components/ui/card';

export const metadata = {
  title: 'Gamificação | Nipo School',
  description: 'Acompanhe seu progresso, conquistas e achievements',
};

async function GamificationContent() {
  const stats = await getGamificationStats();
  
  const nextLevelProgress = stats.progress 
    ? calculateNextLevelProgress(stats.progress.total_points)
    : undefined;

  return (
    <GamificationPanel
      progress={stats.progress}
      pointsHistory={stats.recentHistory}
      achievements={stats.achievements}
      nextLevelProgress={nextLevelProgress}
    />
  );
}

function LoadingSkeleton() {
  return (
    <div className="grid gap-6">
      <Card>
        <CardContent className="pt-6">
          <div className="animate-pulse space-y-4">
            <div className="h-8 bg-muted rounded w-1/3"></div>
            <div className="h-4 bg-muted rounded w-1/4"></div>
            <div className="h-3 bg-muted rounded w-full"></div>
          </div>
        </CardContent>
      </Card>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        {[1, 2, 3].map((i) => (
          <Card key={i}>
            <CardContent className="pt-6">
              <div className="animate-pulse space-y-2">
                <div className="h-4 bg-muted rounded w-1/2"></div>
                <div className="h-8 bg-muted rounded w-1/3"></div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>
    </div>
  );
}

export default function GamificationPage() {
  return (
    <div className="container mx-auto p-6 space-y-6">
      <div className="space-y-2">
        <h1 className="text-3xl font-bold tracking-tight">Gamificação</h1>
        <p className="text-muted-foreground">
          Acompanhe seu progresso, conquiste badges e alcance novos níveis!
        </p>
      </div>

      <Suspense fallback={<LoadingSkeleton />}>
        <GamificationContent />
      </Suspense>
    </div>
  );
}
